INSERT INTO `knowledge_base` (`id`, `title`, `content`, `image_path`, `category`, `sub_category`, `created_by`, `created_at`, `views`, `updated_at`, `article_links`, `article_presentation`, `article_video`, `visible_to_sales`) VALUES
(10, 'How to Access Company Policies and Guidelines', 'All employees can access official company documents through the internal Knowledge Base portal.\r\n\r\nSteps:\r\n\r\nLog in to the system using your company account\r\n\r\nGo to Documentation category\r\n\r\nSelect the file you need (e.g., Employee Handbook, SOPs)\r\n\r\nClick Download or View\r\n\r\nNote: Always check the latest version date before using any document.', NULL, 'Documentation', NULL, NULL, '2026-03-19 03:50:57', 44, '2026-04-17 06:25:09', NULL, NULL, NULL, 1),
(11, 'How to Reset Your Company Email Password', 'If you forgot your email password, follow these steps:\r\n\r\nSteps:\r\n\r\nGo to the email login page\r\n\r\nClick “Forgot Password”\r\n\r\nEnter your registered email\r\n\r\nFollow the OTP verification\r\n\r\nSet a new password\r\n\r\nImportant:\r\n\r\nPassword must be at least 8 characters\r\n\r\nInclude uppercase, lowercase, and numbers', NULL, 'Email', NULL, NULL, '2026-03-19 03:52:02', 6, '2026-03-19 13:17:56', NULL, NULL, NULL, 1),
(12, 'Requesting a New Computer or Laptop', 'Employees needing a new device must submit a request.\r\n\r\nSteps:\r\n\r\nOpen the Ticketing System\r\n\r\nSelect category: Hardware\r\n\r\nChoose Request Type: New Device\r\n\r\nFill in justification and specifications\r\n\r\nSubmit for approval\r\n\r\nProcessing Time: 3–5 working days', NULL, 'Hardware', NULL, NULL, '2026-03-19 03:52:34', 1, '2026-03-28 09:27:52', NULL, NULL, NULL, 1),
(13, 'Troubleshooting Slow Internet Connection', 'If you experience slow internet:\r\n\r\nQuick Fix:\r\n\r\nRestart your router/modem\r\n\r\nDisconnect unused devices\r\n\r\nCheck if issue is system-wide\r\n\r\nIf not resolved:\r\n\r\nSubmit a ticket under Internet Concerns\r\n\r\nInclude:\r\n\r\nLocation\r\n\r\nTime of issue\r\n\r\nScreenshot (if possible)', NULL, 'Internet Concerns', NULL, NULL, '2026-03-19 03:53:25', 3, '2026-03-25 08:55:21', NULL, NULL, NULL, 1),
(14, 'How to Request Office Supplies', 'Employees can request office supplies through procurement.\r\n\r\nSteps:\r\n\r\nSubmit a ticket under Procurement\r\n\r\nSelect Office Supplies Request\r\n\r\nList items needed and quantity\r\n\r\nWait for approval\r\n\r\nNote: Requests are processed every Friday.', NULL, 'Procurement', NULL, NULL, '2026-03-19 03:54:01', 2, '2026-03-23 02:40:58', NULL, NULL, NULL, 1),
(15, 'Installing Approved Company Software', 'Only approved software can be installed on company devices.\r\n\r\nSteps:\r\n\r\nCheck the Approved Software List\r\n\r\nSubmit a request if not installed\r\n\r\nIT team will install remotely or onsite\r\n\r\nReminder:\r\nUnauthorized installations may lead to security issues.', NULL, 'Software', NULL, NULL, '2026-03-19 03:54:32', 7, '2026-04-17 06:18:36', NULL, NULL, NULL, 1),
(16, 'How to Report a System Issue', 'If you encounter system errors or bugs:\r\n\r\nSteps:\r\n\r\nGo to Ticketing System\r\n\r\nSelect Technical Support\r\n\r\nProvide:\r\n\r\nIssue description\r\n\r\nScreenshot or error message\r\n\r\nSteps to reproduce\r\n\r\nSubmit the ticket\r\n\r\nResponse Time: Within 24 hours', NULL, 'Technical Support', NULL, NULL, '2026-03-19 03:55:05', 15, '2026-03-23 08:33:51', NULL, NULL, NULL, 1),
(17, 'How to Request a New Company ID or Access Document', 'Users should submit a ticket with the document name, purpose, and deadline. Attach any supporting file if needed. The admin or HR team will review the request, approve it, and release the document once processed.', NULL, 'Hardware Issue', NULL, NULL, '2026-03-19 05:33:17', 7, '2026-03-19 07:26:03', NULL, NULL, 'https://www.youtube.com/watch?v=xyUQKDE57Ag&list=RDxyUQKDE57Ag&start_radio=1', 1),
(18, 'Unable to Send or Receive Company Email', 'Check if the email account is active, the password is correct, and the internet connection is stable. Clear browser cache, try another browser, and verify if the mailbox is full. If the issue continues, the ticket should be escalated to the IT team.', NULL, 'Email', NULL, NULL, '2026-03-19 05:44:24', 27, '2026-04-17 06:31:17', NULL, NULL, NULL, 1),
(19, 'Printer Not Working or Not Detected', 'Check the power cable, USB/network connection, and printer status. Restart the printer and computer, then verify if the correct printer is selected. If the printer still cannot be detected, check the driver or submit a hardware ticket for inspection.', NULL, 'Hardware', NULL, NULL, '2026-03-19 05:45:17', 4, '2026-04-17 06:18:03', NULL, NULL, NULL, 1),
(29, 'How to Send Email', 'heree', NULL, 'Email', NULL, NULL, '2026-03-19 08:42:08', 13, '2026-04-17 06:18:25', NULL, 'uploads/kb_resources/69bbb6e0283ad_ppt.pptx', NULL, 1),
(34, 'Delayed Purchase Requests (PR) Approval', 'Ensure Complete Information\r\nDouble-check all required fields such as item description, quantity, budget, and justification before submitting the PR.\r\n\r\nFollow Proper Approval Channels\r\nSubmit requests to the correct department or authorized approver to avoid unnecessary routing delays.\r\n\r\nUse Digital Systems\r\nIf available, use procurement or ticketing systems to track and speed up approvals.\r\n\r\nSend Follow-ups Professionally\r\nIf the request is urgent, send a polite follow-up to the approver after a reasonable time.\r\n\r\n💡 Prevention Tips\r\n\r\nSubmit requests ahead of time, especially for urgent needs.\r\n\r\nAlways attach supporting documents or quotations.\r\n\r\nMaintain clear and concise descriptions to avoid back-and-forth clarification.\r\n\r\nCoordinate with your department head for urgent approvals.', 'uploads/kb_images/kb_69c09088337d13.02880856.webp', 'Procurement', NULL, NULL, '2026-03-23 00:59:52', 5, '2026-04-15 07:19:10', NULL, NULL, NULL, 1),
(50, 'How to Set-up New Printer', '', '[\"uploads\\/kb_images\\/kb_69c0accb087658.99405607.jpg\",\"uploads\\/kb_images\\/kb_69c0accb089d89.79283280.jpg\",\"uploads\\/kb_images\\/kb_69c0accb08cba7.93229520.jpg\",\"uploads\\/kb_images\\/kb_69c0accb08f643.78300963.jpg\",\"uploads\\/kb_images\\/kb_69c0accb091b12.52716380.jpg\",\"uploads\\/kb_images\\/kb_69c0accb094975.68082342.jpg\",\"uploads\\/kb_images\\/kb_69c0accb098125.85910527.jpg\",\"uploads\\/kb_images\\/kb_69c0accb09d0a2.24036081.jpg\",\"uploads\\/kb_images\\/kb_69c0accb09ecb8.05333207.jpg\",\"uploads\\/kb_images\\/kb_69c0accb0a0c86.93336413.jpg\"]', 'Printer', NULL, NULL, '2026-03-23 03:00:27', 10, '2026-03-30 01:26:48', NULL, NULL, NULL, 1),
